// Extracted create* factory keeps Counter under 50 lines
function createCounter(initial = 0) {
  const [count, setCount] = createSignal(initial);
  const doubled = createMemo(() => count() * 2);
  return { count, doubled, increment: () => setCount(c => c + 1) };
}

function Counter() {
  const { count, doubled, increment } = createCounter();
  return <button onClick={increment}>{count()} (×2: {doubled()})</button>;
}

import { createSignal, createEffect } from "solid-js";

function AccessibleDialog(props: { open: boolean; onClose: () => void; children: any }) {
  let ref!: HTMLDialogElement;

  // <dialog> gives focus-trap + role="dialog" + Escape key for free
  createEffect(() => {
    props.open ? ref.showModal() : ref.close();
  });

  return (
    <dialog ref={ref} onClose={props.onClose}>
      <button autofocus onClick={props.onClose}>Close</button>
      {props.children}
    </dialog>
  );
}

