type Resolver = (ok: boolean) => void;
const [dlg, setDlg] = createSignal<{ msg: string; resolve: Resolver } | null>(null);

export const confirm = (msg: string) =>
  new Promise<boolean>((resolve) => setDlg({ msg, resolve }));

export function ConfirmDialog() {
  return (
    <Portal>
      <Show when={dlg()}>
        {(d) => <>
          <p>{d().msg}</p>
          <button onClick={() => { d().resolve(true); setDlg(null); }}>OK</button>
          <button onClick={() => { d().resolve(false); setDlg(null); }}>Cancel</button>
        </>}
      </Show>
    </Portal>
  );
}

