import { createSignal, createEffect, createMemo } from "solid-js";

function Counter() {
  // Counter() itself never runs again after mount
  const [count, setCount] = createSignal(0);
  const doubled = createMemo(() => count() * 2); // cached, not recalculated on renders

  createEffect(() => {
    // auto-subscribes to count(); re-runs only when count() changes
    console.log("count is now:", count());
  });

  return (
    <button onClick={() => setCount(c => c + 1)}>
      {count()} × 2 = {doubled()}
    </button>
  );
}
